     1→import * as oidc from "openid-client";
     2→import { type Request, type Response, type NextFunction } from "express";
     3→import type { AuthUser } from "../lib/auth";
     4→import {
     5→  clearSession,
     6→  getOidcConfig,
     7→  getSessionId,
     8→  getSession,
     9→  updateSession,
    10→  type SessionData,
    11→} from "../lib/auth";
    12→
    13→declare global {
    14→  namespace Express {
    15→    interface User extends AuthUser {}
    16→
    17→    interface Request {
    18→      isAuthenticated(): this is AuthedRequest;
    19→      user?: User | undefined;
    20→      /** Resolved user ID — authenticated user ID or guest_<uuid> from cookie */
    21→      resolvedUserId: string;
    22→    }
    23→
    24→    export interface AuthedRequest {
    25→      user: User;
    26→    }
    27→  }
    28→}
    29→
    30→async function refreshIfExpired(
    31→  sid: string,
    32→  session: SessionData,
    33→): Promise<SessionData | null> {
    34→  const now = Math.floor(Date.now() / 1000);
    35→  if (!session.expires_at || now <= session.expires_at) return session;
    36→
    37→  if (!session.refresh_token) return null;
    38→
    39→  try {
    40→    const config = await getOidcConfig();
    41→    const tokens = await oidc.refreshTokenGrant(
    42→      config,
    43→      session.refresh_token,
    44→    );
    45→    session.access_token = tokens.access_token;
    46→    session.refresh_token = tokens.refresh_token ?? session.refresh_token;
    47→    session.expires_at = tokens.expiresIn()
    48→      ? now + tokens.expiresIn()!
    49→      : session.expires_at;
    50→    await updateSession(sid, session);
    51→    return session;
    52→  } catch {
    53→    return null;
    54→  }
    55→}
    56→
    57→export async function authMiddleware(
    58→  req: Request,
    59→  res: Response,
    60→  next: NextFunction,
    61→) {
    62→  req.isAuthenticated = function (this: Request) {
    63→    return this.user != null;
    64→  } as Request["isAuthenticated"];
    65→
    66→  const sid = getSessionId(req);
    67→  if (!sid) {
    68→    next();
    69→    return;
    70→  }
    71→
    72→  const session = await getSession(sid);
    73→  if (!session?.user?.id) {
    74→    await clearSession(res, sid);
    75→    next();
    76→    return;
    77→  }
    78→
    79→  const refreshed = await refreshIfExpired(sid, session);
    80→  if (!refreshed) {
    81→    await clearSession(res, sid);
    82→    next();
    83→    return;
    84→  }
    85→
    86→  req.user = refreshed.user;
    87→  next();
    88→}
    89→

