     1→import * as client from "openid-client";
     2→import crypto from "crypto";
     3→import { type Request, type Response } from "express";
     4→import { db, sessionsTable } from "@workspace/db";
     5→import { eq } from "drizzle-orm";
     6→
     7→/** Minimal auth identity attached to every session and req.user */
     8→export interface AuthUser {
     9→  id: string;
    10→  email?: string | null;
    11→  firstName?: string | null;
    12→  lastName?: string | null;
    13→  profileImageUrl?: string | null;
    14→}
    15→
    16→export const ISSUER_URL = process.env.ISSUER_URL ?? "https://replit.com/oidc";
    17→export const SESSION_COOKIE = "sid";
    18→export const SESSION_TTL = 7 * 24 * 60 * 60 * 1000;
    19→
    20→export interface SessionData {
    21→  user: AuthUser;
    22→  access_token: string;
    23→  refresh_token?: string;
    24→  expires_at?: number;
    25→}
    26→
    27→let oidcConfig: client.Configuration | null = null;
    28→
    29→export async function getOidcConfig(): Promise<client.Configuration> {
    30→  if (!oidcConfig) {
    31→    oidcConfig = await client.discovery(
    32→      new URL(ISSUER_URL),
    33→      process.env.REPL_ID!,
    34→    );
    35→  }
    36→  return oidcConfig;
    37→}
    38→
    39→export async function createSession(data: SessionData): Promise<string> {
    40→  const sid = crypto.randomBytes(32).toString("hex");
    41→  await db.insert(sessionsTable).values({
    42→    sid,
    43→    sess: data as unknown as Record<string, unknown>,
    44→    expire: new Date(Date.now() + SESSION_TTL),
    45→  });
    46→  return sid;
    47→}
    48→
    49→export async function getSession(sid: string): Promise<SessionData | null> {
    50→  const [row] = await db
    51→    .select()
    52→    .from(sessionsTable)
    53→    .where(eq(sessionsTable.sid, sid));
    54→
    55→  if (!row || row.expire < new Date()) {
    56→    if (row) await deleteSession(sid);
    57→    return null;
    58→  }
    59→
    60→  return row.sess as unknown as SessionData;
    61→}
    62→
    63→export async function updateSession(
    64→  sid: string,
    65→  data: SessionData,
    66→): Promise<void> {
    67→  await db
    68→    .update(sessionsTable)
    69→    .set({
    70→      sess: data as unknown as Record<string, unknown>,
    71→      expire: new Date(Date.now() + SESSION_TTL),
    72→    })
    73→    .where(eq(sessionsTable.sid, sid));
    74→}
    75→
    76→export async function deleteSession(sid: string): Promise<void> {
    77→  await db.delete(sessionsTable).where(eq(sessionsTable.sid, sid));
    78→}
    79→
    80→export async function clearSession(
    81→  res: Response,
    82→  sid?: string,
    83→): Promise<void> {
    84→  if (sid) await deleteSession(sid);
    85→  res.clearCookie(SESSION_COOKIE, { path: "/" });
    86→}
    87→
    88→export function getSessionId(req: Request): string | undefined {
    89→  const authHeader = req.headers["authorization"];
    90→  if (authHeader?.startsWith("Bearer ")) {
    91→    return authHeader.slice(7);
    92→  }
    93→  return req.cookies?.[SESSION_COOKIE];
    94→}
    95→

